/**
 * Shop data model for ShieldFinder.
 *
 * Each record:
 *   i   — unique id (string)
 *   n   — name (string)
 *   c   — city (string)
 *   s   — state code (string, e.g. "CA")
 *   a   — address (string)
 *   p   — phone (string)
 *   w   — website URL (string | null)
 *   r   — rating (number, 0–5)
 *   v   — review count (number)
 *   pr  — price range: "$" | "$$" | "$$$"
 *
 *   --- ShieldFinder-specific fields ---
 *   ins — insuranceDirect (boolean) — shop works directly with insurance providers
 *   mob — mobileService  (boolean) — shop offers mobile / on-site service
 *   svc — serviceTypes   (string[]) — subset of:
 *           windshield_replacement | chip_repair | side_window |
 *           rear_window | adas_recalibration
 *
 *   --- Enriched content fields (populated from Outscraper extended export) ---
 *   img     — main photo URL (string | null) — sourced from Outscraper main_photo column
 *   hours   — business hours (object | null) — keys: Monday–Sunday, values: e.g. "9:00 AM – 6:00 PM"
 *             sourced from Outscraper working_hours column (JSON-parsed)
 *   reviews — customer review snippets (array | null) — each item:
 *             { author: string, rating: number, text: string, date: string }
 *             sourced from Outscraper reviews export (separate job)
 */

