// ── State metadata ────────────────────────────────────────────────────────────

export const stateNames = {
  AL: 'Alabama', AK: 'Alaska', AZ: 'Arizona', AR: 'Arkansas', CA: 'California',
  CO: 'Colorado', CT: 'Connecticut', DE: 'Delaware', FL: 'Florida', GA: 'Georgia',
  HI: 'Hawaii', ID: 'Idaho', IL: 'Illinois', IN: 'Indiana', IA: 'Iowa',
  KS: 'Kansas', KY: 'Kentucky', LA: 'Louisiana', ME: 'Maine', MD: 'Maryland',
  MA: 'Massachusetts', MI: 'Michigan', MN: 'Minnesota', MS: 'Mississippi', MO: 'Missouri',
  MT: 'Montana', NE: 'Nebraska', NV: 'Nevada', NH: 'New Hampshire', NJ: 'New Jersey',
  NM: 'New Mexico', NY: 'New York', NC: 'North Carolina', ND: 'North Dakota', OH: 'Ohio',
  OK: 'Oklahoma', OR: 'Oregon', PA: 'Pennsylvania', RI: 'Rhode Island', SC: 'South Carolina',
  SD: 'South Dakota', TN: 'Tennessee', TX: 'Texas', UT: 'Utah', VT: 'Vermont',
  VA: 'Virginia', WA: 'Washington', WV: 'West Virginia', WI: 'Wisconsin', WY: 'Wyoming',
  DC: 'District of Columbia',
};

// ── Slug helpers ──────────────────────────────────────────────────────────────

export function getStateSlug(stateCode) {
  return stateCode.toLowerCase();
}

export function getCitySlug(city) {
  return city.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

export function getShopSlug(shop) {
  return shop.i;
}

// ── Path helpers ──────────────────────────────────────────────────────────────

const LISTINGS_ROUTE = 'shops';

export function getStatePath(stateCode) {
  return `/${LISTINGS_ROUTE}/${getStateSlug(stateCode)}`;
}

export function getCityPath(stateCode, city) {
  return `/${LISTINGS_ROUTE}/${getStateSlug(stateCode)}/${getCitySlug(city)}`;
}

export function getShopPath(shop) {
  return `/${LISTINGS_ROUTE}/${getStateSlug(shop.s)}/${getCitySlug(shop.c)}/${getShopSlug(shop)}`;
}

// ── Lookup helpers ────────────────────────────────────────────────────────────

export function findStateCode(stateSlug) {
  return Object.keys(stateNames).find(
    code => getStateSlug(code) === stateSlug.toLowerCase()
  ) || null;
}

export function getShopsByCity(stateCode) {
  const byCity = {};
  for (const shop of shops) {
    if (shop.s !== stateCode) continue;
    if (!byCity[shop.c]) byCity[shop.c] = [];
    byCity[shop.c].push(shop);
  }
  return Object.entries(byCity).sort((a, b) => a[0].localeCompare(b[0]));
}
